func extractTokenFromHeader(r *http.Request) (string, error) {
	authHeader := r.Header.Get("Authorization")
	if authHeader == "" {
		return "", fmt.Errorf("authorization header is required")
	}

	parts := strings.SplitN(authHeader, " ", 2)
	if len(parts) != 2 || !strings.EqualFold(parts[0], "Bearer") {
		return "", fmt.Errorf("authorization header must be in the format: Bearer <token>")
	}

	token := strings.TrimSpace(parts[1])
	if token == "" {
		return "", fmt.Errorf("token is empty")
	}

	return token, nil
}

func (m *JWTMiddleware) verifyToken(tokenString string) (*UserClaims, error) {
	claims := &UserClaims{}

	token, err := jwt.ParseWithClaims(tokenString, claims, func(token *jwt.Token) (interface{}, error) {
		// Prevent algorithm confusion attacks: ensure the signing method matches expected algorithm
		if token.Method.Alg() != m.allowedAlgorithm {
			return nil, fmt.Errorf("unexpected signing method: %v, expected %s", token.Method.Alg(), m.allowedAlgorithm)
		}

		// Explicitly check it's an HMAC method to prevent "none" algorithm attacks
		if _, ok := token.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("unexpected signing method type: %T", token.Method)
		}

		return m.secretKey, nil
	},
		jwt.WithValidMethods([]string{m.allowedAlgorithm}),
		jwt.WithExpirationRequired(),
		jwt.WithIssuedAt(),
	)

	if err != nil {
		return nil, fmt.Errorf("token parsing failed: %w", err)
	}

	if !token.Valid {
		return nil, fmt.Errorf("token is not valid")
	}

	// Validate required custom claims are present
	if claims.UserID == "" {
		return nil, fmt.Errorf("token missing required claim: user_id")
	}
	if claims.Username == "" {
		return nil, fmt.Errorf("token missing required claim: username")
	}

	return claims, nil
}

